/**
 * @fileOverview Shërbimi i avancuar për kërkimin e adresave në Kosovë (Fuzzy Search).
 * Mbështet kërkimin për qytete, fshatra, biznese dhe lagje me prioritizim të qendrave urbane.
 */

export interface SearchResult {
  name: string;
  lat: number;
  lng: number;
  displayName: string;
  type?: string;
}

/**
 * Normalizon tekstin për kërkim më tolerant (heq ç/ë dhe aksentet).
 */
function normalizeQuery(query: string): string {
  return query
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/ç/g, 'c')
    .replace(/ë/g, 'e')
    .trim();
}

/**
 * Kërkon lokacione në Kosovë duke përdorur Photon (OSM) me prioritizim të qyteteve.
 */
export async function searchLocations(query: string): Promise<SearchResult[]> {
  if (!query || query.trim().length < 2) return [];

  const cleanedQuery = normalizeQuery(query);
  
  try {
    // Shtojmë bias për qendrën e Kosovës dhe kufij strikt
    const bbox = "20.0,41.8,21.8,43.3";
    const url = `https://photon.komoot.io/api/?q=${encodeURIComponent(cleanedQuery)}&lat=42.6629&lon=21.1655&limit=15&location_bias_scale=1.0&bbox=${bbox}`;
    
    const response = await fetch(url);
    const data = await response.json();

    if (!data || !data.features) return [];

    return data.features
      .filter((f: any) => {
        const coords = f.geometry.coordinates;
        // Sigurohemi që rezultati është brenda kufijve të Kosovës
        return coords[1] >= 41.8 && coords[1] <= 43.3 && coords[0] >= 20.0 && coords[0] <= 21.8;
      })
      .map((feature: any) => {
        const p = feature.properties;
        const coords = feature.geometry.coordinates;
        const name = p.name || p.street || p.district || p.city || "Lokacion";
        const normalizedName = normalizeQuery(name);
        
        let score = 0;
        // Prioritet maksimal për përputhje ekzakte të emrit
        if (normalizedName === cleanedQuery) score += 500;
        else if (normalizedName.startsWith(cleanedQuery)) score += 200;

        const type = p.osm_value || p.type || "";
        // Prioritizojmë qytetet mbi fshatrat (Fix: Prizren vs Zhur)
        const priorities: Record<string, number> = { 
          city: 1000, 
          town: 800, 
          village: 100, 
          hamlet: 50, 
          residential: 10 
        };
        score += (priorities[type] || 0);

        return {
          name: name,
          lat: coords[1],
          lng: coords[0],
          displayName: `${name}${p.city ? `, ${p.city}` : ""}${p.district ? ` (${p.district})` : ""}`,
          type: type,
          score: score
        };
      })
      .sort((a: any, b: any) => b.score - a.score)
      .map(({ score, ...rest }: any) => rest);
  } catch (error) {
    console.error("Kërkimi dështoi:", error);
    return [];
  }
}
