"use client"

import { useState, useEffect, useMemo } from "react";
import dynamic from "next/dynamic";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { 
  Search, Navigation, Loader2, MapPin, Play, Target, X, 
  Zap, ShieldAlert, Timer, Radio, Activity, ChevronRight, 
  RotateCcw, ArrowUp, ArrowUpLeft, ArrowUpRight, Clock
} from "lucide-react";
import { useFirestore, useCollection, useMemoFirebase, addDocumentNonBlocking, useUser, useDoc } from "@/firebase";
import { collection, query, orderBy, doc, where, limit } from "firebase/firestore";
import { useDriving } from "@/context/driving-context";
import { calculateRoutes } from "@/services/navigation/routeService";
import { searchLocations, SearchResult } from "@/services/navigation/geocodingService";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";

const DriveRankMap = dynamic(() => import("@/components/map/DriveRankMap"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-zinc-950 flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-accent" /></div>
});

type ReportType = 'Radar' | 'Polici' | 'Kontrollë';

export default function NavigationPage() {
  const { 
    speed, currentCoords, heading,
    destination, routeData, availableRoutes, isNavigating,
    currentStep, distanceToNextStep, dynamicZoom,
    setDestination, setRouteData, setAvailableRoutes, setIsNavigating, clearNavigation
  } = useDriving();
  
  const { user } = useUser();
  const db = useFirestore();
  const { toast } = useToast();
  
  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState<SearchResult[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [forceCenter, setForceCenter] = useState(0);
  const [isReporting, setIsReporting] = useState<ReportType | null>(null);

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, db]);
  const { data: profile } = useDoc(profileRef);

  const threeHoursAgo = useMemo(() => {
    const d = new Date();
    d.setHours(d.getHours() - 3);
    return d.toISOString();
  }, []);

  const radarQuery = useMemoFirebase(() => {
    if (!db) return null;
    return query(
      collection(db, "radar_reports"), 
      where("createdAt", ">=", threeHoursAgo),
      orderBy("createdAt", "desc"),
      limit(100)
    );
  }, [db, threeHoursAgo]);
  
  const { data: alerts } = useCollection(radarQuery);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (searchQuery.trim().length >= 2) {
        setIsSearching(true);
        try {
          const results = await searchLocations(searchQuery);
          setSearchResults(results);
        } catch (e) { console.error("Search failed:", e); }
        finally { setIsSearching(false); }
      } else { setSearchResults([]); }
    }, 400);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  const handleSelectDestination = async (result: any) => {
    setDestination(result);
    setSearchQuery("");
    setSearchResults([]);
    
    if (!currentCoords) {
      toast({ variant: "destructive", title: "GPS 📍", description: "Lejoni GPS-in për navigim." });
      return;
    }

    try {
      const routes = await calculateRoutes(currentCoords, { lat: result.lat, lng: result.lng });
      if (routes.length > 0) {
        setAvailableRoutes(routes);
        setRouteData(routes[0]);
        toast({ title: "RRUGA U GJET 🏁", description: `Udhëtimi drejt ${result.name} është gati.` });
      } else {
        toast({ variant: "destructive", title: "GABIM ❌", description: "Nuk u gjet asnjë rrugë." });
      }
    } catch (e) {
      toast({ variant: "destructive", title: "GABIM ❌", description: "Dështoi llogaritja e rrugëtimit." });
    }
  };

  const handleQuickReport = async (type: ReportType) => {
    if (!db || !currentCoords || !user?.uid) {
      toast({ variant: "destructive", title: "GABIM 📍", description: "Lidhja GPS kërkohet." });
      return;
    }
    setIsReporting(type);
    
    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type,
      lat: currentCoords.lat,
      lng: currentCoords.lng,
      location: "Raport Live",
      city: profile?.city || "Kosovë",
      createdAt: new Date().toISOString(),
      userId: user?.uid
    });
    
    setTimeout(() => {
      setIsReporting(null);
      toast({ title: "RAPORTUAR ✅", description: `${type} shënuar në hartë.` });
    }, 500);
  };

  const handleStartNav = () => {
    if (!routeData) return;
    setIsNavigating(true);
    toast({ title: "MODI DRIVING AKTIV 🔥", description: "Vozitni me kujdes, rruga e bardhë do t'ju ndjekë!" });
  };

  const handleStopNav = () => {
    setIsNavigating(false);
    clearNavigation();
  };

  const getManeuverIcon = (type: string, modifier?: string) => {
    if (type.includes('roundabout')) return <RotateCcw className="w-8 h-8 text-accent" />;
    if (modifier === 'left') return <ArrowUpLeft className="w-8 h-8 text-accent" />;
    if (modifier === 'right') return <ArrowUpRight className="w-8 h-8 text-accent" />;
    return <ArrowUp className="w-8 h-8 text-accent" />;
  };

  return (
    <div className="flex flex-col h-screen bg-black relative overflow-hidden">
      <div className="absolute inset-0 z-0">
        <DriveRankMap 
          userLocation={currentCoords} 
          heading={heading}
          route={routeData?.coordinates || null} 
          alerts={alerts || []}
          destination={destination}
          isNavigating={isNavigating}
          forceCenter={forceCenter}
          speed={speed}
          zoom={dynamicZoom}
        />
      </div>

      <div className="absolute top-12 left-4 right-4 z-50 pointer-events-none flex flex-col gap-3">
        {!isNavigating ? (
          <div className="relative pointer-events-auto">
            <Card className="glass-card p-3 rounded-2xl border-white/10 shadow-2xl flex items-center gap-3 bg-zinc-950/90 backdrop-blur-3xl">
              <Search className="w-5 h-5 text-accent shrink-0" />
              <Input 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Kërko fshatra & qytete..."
                className="bg-transparent border-none h-11 p-0 text-white placeholder:text-zinc-500 focus-visible:ring-0 font-black italic uppercase text-base" 
              />
              {isSearching && <Loader2 className="w-4 h-4 animate-spin text-accent" />}
              {(searchQuery || destination) && (
                <button onClick={() => { clearNavigation(); setSearchQuery(""); }} className="text-zinc-500 hover:text-white p-1">
                  <X className="w-5 h-5" />
                </button>
              )}
            </Card>

            {searchResults.length > 0 && (
              <Card className="mt-2 glass-card border-white/10 rounded-2xl shadow-2xl overflow-hidden max-h-[350px] overflow-y-auto no-scrollbar bg-zinc-950/98 relative z-[60]">
                {searchResults.map((result, idx) => (
                  <button 
                    key={idx}
                    onClick={() => handleSelectDestination(result)}
                    className="w-full p-4 flex items-center gap-4 hover:bg-white/10 border-b border-white/5 last:border-none text-left active:bg-accent/20 transition-colors"
                  >
                    <div className="w-10 h-10 rounded-xl bg-accent/10 flex items-center justify-center shrink-0 border border-accent/20">
                      <MapPin className="w-5 h-5 text-accent" />
                    </div>
                    <div className="flex flex-col min-w-0">
                      <span className="text-sm font-black text-white uppercase italic truncate">{result.name}</span>
                      <span className="text-[9px] font-bold text-zinc-500 uppercase truncate mt-0.5">{result.displayName}</span>
                    </div>
                  </button>
                ))}
              </Card>
            )}
          </div>
        ) : (
          <div className="flex flex-col gap-2 pointer-events-auto">
             <Card className="glass-card p-4 rounded-[2.5rem] border-accent/30 shadow-[0_0_40px_rgba(77,224,244,0.3)] bg-zinc-950/95 backdrop-blur-3xl border-b-4 border-accent/20">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-accent/20 rounded-2xl flex items-center justify-center shadow-xl border border-accent/30">
                      {currentStep ? getManeuverIcon(currentStep.type, currentStep.modifier) : <Navigation className="w-8 h-8 text-accent" />}
                    </div>
                    <div className="flex flex-col">
                      <div className="flex items-baseline gap-2">
                        <span className="text-2xl font-black text-white italic">
                          {distanceToNextStep >= 1000 ? `${(distanceToNextStep / 1000).toFixed(1)} km` : `${distanceToNextStep} m`}
                        </span>
                        <span className="text-[10px] font-black text-accent uppercase tracking-widest">LARG</span>
                      </div>
                      <span className="text-sm font-black text-white uppercase italic truncate max-w-[160px] leading-tight">
                        {currentStep?.instruction || "Vazhdo drejt"}
                      </span>
                    </div>
                  </div>
                  <div className="flex flex-col items-end">
                    <span className="text-4xl font-black text-white italic leading-none tabular-nums">{speed}</span>
                    <span className="text-[9px] font-black text-accent uppercase tracking-widest mt-1">KM/H</span>
                  </div>
                </div>
             </Card>
             
             {distanceToNextStep < 300 && currentStep?.type.includes('roundabout') && (
               <div className="bg-red-600 text-white font-black text-xs p-2.5 rounded-2xl text-center uppercase italic animate-pulse shadow-2xl border-2 border-white/20">
                 🚨 KUJDES: RRETHRRROTULLIM PËRPARA!
               </div>
             )}
          </div>
        )}
      </div>

      <div className="absolute right-4 top-1/2 -translate-y-1/2 z-40 flex flex-col gap-3 pointer-events-auto">
         <Button 
            onClick={() => handleQuickReport('Radar')} 
            disabled={!!isReporting}
            className="w-16 h-16 rounded-2xl bg-red-600 hover:bg-red-700 text-white shadow-2xl flex items-center justify-center active:scale-95 transition-all border-b-4 border-red-900"
         >
           {isReporting === 'Radar' ? <Loader2 className="w-7 h-7 animate-spin" /> : <Radio className="w-8 h-8" />}
         </Button>
         <Button 
            onClick={() => handleQuickReport('Polici')} 
            disabled={!!isReporting}
            className="w-16 h-16 rounded-2xl bg-blue-600 hover:bg-blue-700 text-white shadow-2xl flex items-center justify-center active:scale-95 transition-all border-b-4 border-blue-900"
         >
           {isReporting === 'Polici' ? <Loader2 className="w-7 h-7 animate-spin" /> : <ShieldAlert className="w-8 h-8" />}
         </Button>
      </div>

      <div className="absolute bottom-32 right-4 z-40">
        <Button 
          onClick={() => setForceCenter(prev => prev + 1)}
          className="w-14 h-14 rounded-2xl bg-zinc-950/90 border border-white/10 text-white shadow-2xl flex items-center justify-center active:scale-95 transition-all"
        >
          <Target className="w-7 h-7 text-accent" />
        </Button>
      </div>

      {routeData && !isNavigating && (
        <div className="absolute bottom-24 left-4 right-4 z-40 space-y-3 animate-in slide-in-from-bottom-5 duration-500">
          <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
            {availableRoutes.map((route, idx) => (
              <Card 
                key={idx}
                onClick={() => setRouteData(route)}
                className={cn(
                  "flex-shrink-0 p-4 rounded-2xl border transition-all cursor-pointer min-w-[150px] shadow-2xl",
                  routeData === route ? "bg-accent/20 border-accent shadow-accent/20" : "bg-zinc-950/90 border-white/10"
                )}
              >
                <div className="flex flex-col">
                  <div className="flex items-center justify-between mb-1">
                    <span className="text-[8px] font-black uppercase tracking-widest text-muted-foreground">
                      {idx === 0 ? "MË E SHPEJTA 🔥" : "ALTERNATIVE"}
                    </span>
                    <Zap className={cn("w-3 h-3", routeData === route ? "text-accent" : "text-zinc-600")} />
                  </div>
                  <span className="text-xl font-black text-white italic">
                    {Math.round(route.duration / 60)} MIN
                  </span>
                  <span className="text-[10px] font-bold text-accent uppercase">
                    {(route.distance / 1000).toFixed(1)} KM • {route.summary}
                  </span>
                </div>
              </Card>
            ))}
          </div>

          <Card className="glass-card p-4 rounded-[2.5rem] border-accent/20 shadow-2xl bg-zinc-950/95">
            <div className="flex gap-3">
              <Button onClick={() => { clearNavigation(); setSearchQuery(""); }} variant="outline" className="flex-1 h-16 rounded-2xl font-black text-[11px] uppercase border-white/10 text-zinc-500 hover:text-white">
                ANULO
              </Button>
              <Button onClick={handleStartNav} className="flex-[2.5] h-16 bg-accent hover:bg-accent/90 text-background font-black text-xl uppercase italic rounded-2xl shadow-xl border-b-4 border-accent/50">
                NISU TANI <Play className="w-7 h-7 ml-2 fill-current" />
              </Button>
            </div>
          </Card>
        </div>
      )}

      {isNavigating && (
        <div className="absolute bottom-28 left-4 right-4 z-40 pointer-events-none flex items-end justify-between">
           <div className="relative w-24 h-24">
              <div className="absolute inset-0 bg-accent/20 rounded-full blur-2xl animate-pulse" />
              <div className="relative w-full h-full bg-zinc-950 border-4 border-accent/30 rounded-full flex flex-col items-center justify-center shadow-2xl">
                 <Activity className="w-4 h-4 text-accent mb-1" />
                 <span className="text-3xl font-black text-white italic leading-none tabular-nums">{speed}</span>
                 <span className="text-[8px] font-black text-accent uppercase">KM/H</span>
              </div>
           </div>
           
           <div className="flex flex-col gap-2 items-end pointer-events-auto">
             <Button 
                onClick={handleStopNav} 
                variant="destructive" 
                className="w-24 h-12 rounded-2xl font-black uppercase text-xs shadow-2xl border-b-4 border-red-900"
             >
               STOP
             </Button>
           </div>
        </div>
      )}

      <BottomNav />
    </div>
  );
}